3_real_world_example.code:
function identify() {
  return `I am ${this.name}`;
}

const user1 = { name: 'Alice', speak: identify };
const user2 = { name: 'Bob', speak: identify };

// We are calling the exact same function in memory.
// But the object to the left of the dot determines 'this'.
console.log(user1.speak()); // 'I am Alice'
console.log(user2.speak()); // 'I am Bob'

6_edge_case.code:
const obj = {
  name: 'Charlie',
  speak() { console.log(this.name); }
};

obj.speak(); // 'Charlie'

const extracted = obj.speak;
extracted(); // undefined! (There is no object to the left of the dot when called)
